#include <stdio.h>
#include <string.h>
#include <cuda_runtime.h>

#include "../common.h"
#include "../util/cuda/cuda.h"
#include "./kernel_gpu_cuda_wrapper.h"

extern __global__ void findK_cuda(long height,
                                  knode *knodesD,
                                  long knodes_elem,
                                  record *recordsD,
                                  long *currKnodeD,
                                  long *offsetD,
                                  int *keysD,
                                  record *ansD);

extern "C" void
kernel_gpu_cuda_wrapper(record *records,
                        long records_mem,
                        knode *knodes,
                        long knodes_elem,
                        long knodes_mem,
                        int order,
                        long maxheight,
                        int count,
                        long *currKnode,
                        long *offset,
                        int *keys,
                        record *ans) {
    setdevice();

    record *recordsD = NULL;
    knode *knodesD = NULL;
    long *currKnodeD = NULL;
    long *offsetD = NULL;
    int *keysD = NULL;
    record *ansD = NULL;

    cudaMalloc((void **)&recordsD, records_mem);
    cudaMalloc((void **)&knodesD, knodes_mem);
    cudaMalloc((void **)&currKnodeD, count * sizeof(long));
    cudaMalloc((void **)&offsetD, count * sizeof(long));
    cudaMalloc((void **)&keysD, count * sizeof(long)); // preserve source allocation behavior
    cudaMalloc((void **)&ansD, count * sizeof(record));
    checkCUDAError("cudaMalloc");

    cudaMemcpy(recordsD, records, records_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(knodesD, knodes, knodes_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(currKnodeD, currKnode, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(offsetD, offset, count * sizeof(long), cudaMemcpyHostToDevice);
    cudaMemcpy(keysD, keys, count * sizeof(int), cudaMemcpyHostToDevice);
    cudaMemcpy(ansD, ans, count * sizeof(record), cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy HtoD");

    int threads = (order < 1024) ? order : 1024;
    int blocks = count;

    printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n", blocks, threads);

    findK_cuda<<<blocks, threads>>>(maxheight,
                                    knodesD,
                                    knodes_elem,
                                    recordsD,
                                    currKnodeD,
                                    offsetD,
                                    keysD,
                                    ansD);
    checkCUDAError("kernel launch");
    cudaDeviceSynchronize();
    checkCUDAError("kernel sync");

    cudaMemcpy(ans, ansD, count * sizeof(record), cudaMemcpyDeviceToHost);
    checkCUDAError("cudaMemcpy DtoH");

    cudaFree(recordsD);
    cudaFree(knodesD);
    cudaFree(currKnodeD);
    cudaFree(offsetD);
    cudaFree(keysD);
    cudaFree(ansD);
    checkCUDAError("cudaFree");
}

extern "C" void
kernel_gpu_opencl_wrapper(record *records,
                          long records_mem,
                          knode *knodes,
                          long knodes_elem,
                          long knodes_mem,
                          int order,
                          long maxheight,
                          int count,
                          long *currKnode,
                          long *offset,
                          int *keys,
                          record *ans) {
    kernel_gpu_cuda_wrapper(records, records_mem, knodes, knodes_elem, knodes_mem,
                            order, maxheight, count, currKnode, offset, keys, ans);
}

